"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[190266],{864497:e=>{e.exports=JSON.parse('{"tag":{"label":"client","permalink":"/dst-api-webdocs/docs/tags/client","allTagsPath":"/dst-api-webdocs/docs/tags","count":18,"items":[{"id":"game-scripts/prefabs/balloon_held_child","title":"Balloon Held Child","description":"Manages network synchronization and client-side animation of a held balloon prop attached to an entity.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/balloon_held_child"},{"id":"game-scripts/prefabs/charlieresidue","title":"Charlieresidue","description":"A classified client-side visual effect entity that tracks a target and renders Charlie\'s residue, decaying when activated or vision conditions change.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/charlieresidue"},{"id":"game-scripts/components/focalpoint","title":"Focalpoint","description":"Manages camera focal point targeting on the client, updating camera offset based on prioritized sources and distance constraints.","permalink":"/dst-api-webdocs/docs/game-scripts/components/focalpoint"},{"id":"game-scripts/prefabs/fx","title":"Fx","description":"Generates and returns a list of Prefab instances for client-side visual and audio effects, supporting dynamic assets, animation, tinting, sound, and custom behaviors.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/fx"},{"id":"game-scripts/prefabs/ghost_transform_overlay_fx","title":"Ghost Transform Overlay Fx","description":"Renders a visual overlay effect (light and animation) used during player ghost transformation sequences.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/ghost_transform_overlay_fx"},{"id":"game-scripts/components/hudindicatablemanager","title":"Hudindicatablemanager","description":"Manages a collection of HUD-indicatable items on the client side for display purposes.","permalink":"/dst-api-webdocs/docs/game-scripts/components/hudindicatablemanager"},{"id":"game-scripts/components/inventoryitem_replica","title":"Inventoryitem Replica","description":"Manages network-replicated properties and synchronization of inventory items between server and client, including pickup restrictions, deploy modes, weapon stats, and usage state serialization.","permalink":"/dst-api-webdocs/docs/game-scripts/components/inventoryitem_replica"},{"id":"game-scripts/prefabs/lavaarena_crowdstand","title":"Lavaarena Crowdstand","description":"Provides client-side visual decoration for the Lava Arena spectator stands, including banners, fences, and audience members.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lavaarena_crowdstand"},{"id":"game-scripts/prefabs/lavaarena_rhinobumpfx","title":"Lavaarena Rhinobumpfx","description":"Spawns a non-networked particle effect entity when a rhino-like entity collides, used only on the client for visual feedback.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lavaarena_rhinobumpfx"},{"id":"game-scripts/components/lunarhailbirdsoundmanager","title":"Lunarhailbirdsoundmanager","description":"Manages audio levels for the lunar hail bird event, controlling ambient sound playback based on event intensity.","permalink":"/dst-api-webdocs/docs/game-scripts/components/lunarhailbirdsoundmanager"},{"id":"game-scripts/prefabs/miasma_cloud_fx","title":"Miasma Cloud Fx","description":"Manages client-side visual particle effects (smoke and embers) for miasma clouds, including dynamic attachment/detachment based on camera distance and orientation.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/miasma_cloud_fx"},{"id":"game-scripts/prefabs/moose_nest_fx","title":"Moose Nest Fx","description":"Creates non-persistent, client-side particle and sound effects for moose nest interactions (idle and hit states), using a proxy transform for positioning and synchronized animation.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/moose_nest_fx"},{"id":"game-scripts/prefabs/nightsword_lightsbane_fx","title":"Nightsword Lightsbane Fx","description":"Creates and manages particle effects for the Nightsword Lightsbane weapon attack animation on the client.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/nightsword_lightsbane_fx"},{"id":"game-scripts/stategraphs/SGwilsonghost_client","title":"Sgwilsonghost Client","description":"Manages client-side state transitions and movement prediction for Wilson\'s ghost form, synchronizing animation, locomotion, and action previewing with server confirmation.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGwilsonghost_client"},{"id":"game-scripts/prefabs/spooked_fx","title":"Spooked Fx","description":"Creates short-lived, client-side visual and audio effect prefabs for the Spooked event\'s spider and worm spawn animations.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/spooked_fx"},{"id":"game-scripts/components/transparentonsanity","title":"Transparentonsanity","description":"Adjusts an entity\'s transparency and sound volume based on the player\'s sanity and combat state, with optional custom logic.","permalink":"/dst-api-webdocs/docs/game-scripts/components/transparentonsanity"},{"id":"game-scripts/prefabs/winona_holoitems","title":"Winona Holoitems","description":"Creates and manages networked holographic placeholder prefabs for Winona\'s holographic items, handling visual states, lifecycle, and interaction with inventory components.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/winona_holoitems"},{"id":"game-scripts/prefabs/writeable_classified","title":"Writeable Classified","description":"Serves as a client-side helper entity that coordinates with its parent writeable item to manage classified data attachment and lifecycle.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/writeable_classified"}],"unlisted":false}}')}}]);